import{_ as i,o as t,c as a,a2 as d}from"./chunks/framework.C90q7Ucc.js";const u=JSON.parse('{"title":"生命周期与解耦评估","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/lifecycle-and-decoupling-audit.md","filePath":"architecture/lifecycle-and-decoupling-audit.md","lastUpdated":1780753561000}'),r={name:"architecture/lifecycle-and-decoupling-audit.md"};function l(o,e,s,n,c,p){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="生命周期与解耦评估" tabindex="-1">生命周期与解耦评估 <a class="header-anchor" href="#生命周期与解耦评估" aria-label="Permalink to &quot;生命周期与解耦评估&quot;">​</a></h1><p>本文记录一次面向维护者的架构评估，回答三个问题：</p><ul><li>当前项目实际有几个主要进程，生命周期如何启动和停止。</li><li>哪些运行时边界由谁拥有，哪些只是 bridge 内部的调度或展示机制。</li><li>哪些模块已经有清晰边界，哪些地方值得继续解耦。</li></ul><p>本文是现状审计，不是消息链路说明，也不是强制改造方案。消息投递、lane、mirror 渲染链路的细节见 <a href="./current">当前架构</a>；本文只保留它们对生命周期和解耦判断有影响的结论。</p><h2 id="进程拓扑" tabindex="-1">进程拓扑 <a class="header-anchor" href="#进程拓扑" aria-label="Permalink to &quot;进程拓扑&quot;">​</a></h2><p>CodeLark 的常见稳态由几个进程或外部运行体组成。</p><table tabindex="0"><thead><tr><th>运行体</th><th>入口</th><th>生命周期 owner</th><th>主要状态文件</th><th>职责</th></tr></thead><tbody><tr><td>CLI 一次性进程</td><td><code>src/entrypoints/cli.ts</code></td><td>用户命令 <code>codelark ...</code></td><td>无长期状态</td><td>执行 <code>run</code>、<code>start</code>、<code>status</code>、<code>stop</code>、<code>setup</code> 等本地服务管理动作。</td></tr><tr><td>UI server</td><td><code>src/operator-ui/server.ts</code></td><td><code>src/local-service/manager.ts</code> 的 <code>ensureUiServerRunning()</code></td><td><code>~/.codelark/runtime/ui-server.json</code></td><td>提供本地工作台页面和 API，默认监听 <code>4781</code>，端口被占用时向后探测。</td></tr><tr><td>Bridge daemon</td><td><code>src/entrypoints/daemon.ts</code></td><td><code>src/local-service/manager.ts</code> 或 <code>scripts/daemon.sh</code></td><td><code>~/.codelark/runtime/status.json</code>、<code>bridge.pid</code>、instance lock</td><td>连接 IM 通道、运行消息主循环、协调命令、turn、mirror、权限和 delivery。</td></tr><tr><td>Feishu WebSocket 连接</td><td><code>src/channels/feishu/adapter.ts</code></td><td>Bridge daemon 内的 adapter lifecycle</td><td>adapter 内存状态、audit log</td><td>接收飞书事件，转换成 <code>InboundMessage</code>，并发送文本、文件、卡片和流式卡片更新。</td></tr><tr><td>Codex SDK/exec 子进程</td><td><code>src/runtime/codex/provider.ts</code></td><td>Bridge daemon 内的 Codex SDK provider</td><td>Codex 自有 <code>~/.codex</code> 数据</td><td>通过 Codex SDK/exec 执行 prompt，产出 SSE 风格事件。</td></tr><tr><td>Codex pty child</td><td><code>src/runtime/codex/pty-provider.ts</code></td><td>Bridge daemon 内的 pty provider</td><td>内存中的 pty screen map、Codex JSONL</td><td>在 daemon 内创建 pty child，注入 prompt，读取屏幕和 JSONL mirror。</td></tr><tr><td>Codex tmux session</td><td><code>src/runtime/codex/tmux-provider.ts</code>、<code>src/bridge/tmux/*</code></td><td>tmux server + Bridge daemon 编排</td><td>tmux session、Codex JSONL</td><td>在 tmux 中运行 Codex TUI，Bridge 通过 tmux CLI 注入输入和捕获屏幕。</td></tr><tr><td>Claude tmux session</td><td><code>src/runtime/claude/tmux-provider.ts</code>、<code>src/bridge/tmux/*</code></td><td>tmux server + Bridge daemon 编排</td><td>tmux session、Claude JSONL</td><td>默认 Claude Code provider；在 tmux 中运行 Claude Code TUI，Bridge 通过 tmux CLI 注入输入和捕获屏幕。</td></tr><tr><td>Claude pty child</td><td><code>src/runtime/claude/pty-provider.ts</code></td><td>Bridge daemon 内的 Claude pty provider</td><td>内存中的 pty session map、Claude JSONL</td><td>在 pty 中运行 Claude Code，注入 prompt，读取屏幕和 JSONL mirror。</td></tr></tbody></table><p><code>codelark run</code> 会尝试启动 UI server 和 Bridge daemon；<code>codelark start</code> 只启动 Bridge daemon。启动 Bridge 前，<code>src/local-service/manager.ts</code> 会为当前 CodeLark 配置初始化专属 lark-cli 运行环境，并把 <code>LARK_CHANNEL_CONFIG</code> / <code>LARKSUITE_CLI_CONFIG_DIR</code> 注入 daemon。Linux 下 <code>scripts/daemon.sh start</code> 使用 <code>setsid</code> 或 <code>nohup</code> 启动 <code>dist/daemon.mjs</code>，macOS 走 launchctl，Windows 走 PowerShell supervisor。</p><h2 id="bridge-daemon-启动生命周期" tabindex="-1">Bridge Daemon 启动生命周期 <a class="header-anchor" href="#bridge-daemon-启动生命周期" aria-label="Permalink to &quot;Bridge Daemon 启动生命周期&quot;">​</a></h2><p>Bridge daemon 的启动路径集中在 <code>src/entrypoints/daemon.ts</code>：</p><ol><li>抢占 bridge instance lock，避免重复 daemon。</li><li>运行本地存储迁移。</li><li>读取配置，创建 <code>JsonFileStore</code>、<code>PendingPermissions</code> 和 <code>CodexRoutingProvider</code>。</li><li>通过 <code>initBridgeContext()</code> 注入 store、llm、permission gateway 和 lifecycle hook。</li><li>调用 <code>bridgeManager.start()</code>。</li><li><code>bridgeManager.start()</code> 同步通道 adapter，启动成功后设置 <code>state.running = true</code>。</li><li>为每个运行中的 adapter 启动消费 loop。</li><li>启动定时 reconcile：adapter 配置、session health、terminal runtime、mirror poll。</li><li>写入 <code>bridge.pid</code> 和 <code>status.json</code>。</li><li>监听 <code>SIGTERM</code>、<code>SIGINT</code>、<code>SIGHUP</code>，停止 bridge、释放锁并写入停止状态。</li></ol><p><code>src/local-service/manager.ts</code> 负责从 CLI 侧启动和停止 daemon。它在启动前检查 status、PID、preflight、start lock 和 stale lock，然后 detached spawn <code>dist/daemon.mjs</code>，再轮询 <code>status.json</code> 等待 daemon 报告 <code>running=true</code>。</p><h2 id="内部生命周期边界" tabindex="-1">内部生命周期边界 <a class="header-anchor" href="#内部生命周期边界" aria-label="Permalink to &quot;内部生命周期边界&quot;">​</a></h2><p>这几个机制容易被误解成独立进程或通用事件总线，但当前实现都运行在 Bridge daemon 内：</p><table tabindex="0"><thead><tr><th>机制</th><th>生命周期 owner</th><th>当前边界</th><th>解耦判断</th></tr></thead><tbody><tr><td>Adapter ingress</td><td>Bridge manager + adapter runtime</td><td>adapter 把平台事件转成 <code>InboundMessage</code>，adapter runtime 负责消费和调度。</td><td>边界可用，但 manager 仍承担太多路由细节。</td></tr><tr><td>Lane 调度</td><td>adapter runtime + session executor</td><td>lane 表达消息之间的等待关系；同一工作会话串行，不同会话、控制动作和部分长 I/O 可并行。</td><td>概念已经清楚，应该继续从 manager 中拆成独立 ingress/router 服务。</td></tr><tr><td>Turn progress</td><td>interactive turn / mirror turn</td><td>SDK stream 和 JSONL mirror 都写入 <code>UnifiedTurnProgressState</code>。</td><td>这是当前最值得保留和强化的内部语义边界。</td></tr><tr><td>Mirror reconcile</td><td>mirror runtime</td><td><code>fs.watch</code> / poll 只唤醒 reconcile；订阅间有界并发，单订阅内按 cursor 顺序处理。</td><td>边界清晰，复杂度来自 JSONL 不确定性、回声抑制和终态归属。</td></tr><tr><td>Stream UI</td><td>stream feedback + channel adapter</td><td>runtime-neutral 层只表达 text/history/tools/tasks/status/finalize；Feishu adapter 负责 CardKit 状态机。</td><td>抽象方向正确，但能力协商仍分散。</td></tr></tbody></table><p>因此，本文后续不再重复消息投递、lane 分类、mirror records 或 Feishu 卡片 diff 的完整链路。评估重点放在 owner 是否清楚、状态是否集中、模块是否容易单测。</p><h2 id="现有好的边界" tabindex="-1">现有好的边界 <a class="header-anchor" href="#现有好的边界" aria-label="Permalink to &quot;现有好的边界&quot;">​</a></h2><p>以下边界值得保留：</p><ul><li><code>InboundMessage</code> / <code>OutboundMessage</code>：通道抽象明确，平台事件不会直接流入 bridge 业务层。</li><li><code>ChannelChat -&gt; BridgeSession</code>：IM chat 不直接绑定 runtime thread，便于切换和接管。</li><li><code>CodexRoutingProvider</code>：Codex SDK、Codex pty、Codex tmux、Claude tmux、Claude pty、Claude sdk 有统一 <code>LLMProvider.streamChat()</code> 入口。</li><li><code>UnifiedTurnProgressState</code>：SDK stream 和 mirror record 的共同语义模型。</li><li><code>MirrorJsonlSource</code>：Codex 和 Claude JSONL source 共享 mirror runtime。</li><li><code>TurnCoordinator</code>：active IM turn 和外部 terminal/mirror 终态之间有显式 claim 机制。</li><li><code>local-service/manager.ts</code>：CLI 侧服务管理和 daemon 内部 bridge 生命周期分离。</li></ul><h2 id="主要耦合点" tabindex="-1">主要耦合点 <a class="header-anchor" href="#主要耦合点" aria-label="Permalink to &quot;主要耦合点&quot;">​</a></h2><h3 id="_1-bridge-host-manager-ts-是过厚的宿主总管" tabindex="-1">1. <code>bridge/host/manager.ts</code> 是过厚的宿主总管 <a class="header-anchor" href="#_1-bridge-host-manager-ts-是过厚的宿主总管" aria-label="Permalink to &quot;1. `bridge/host/manager.ts` 是过厚的宿主总管&quot;">​</a></h3><p>该文件同时承担：</p><ul><li>adapter lifecycle</li><li>adapter loop 到 message handling</li><li>command routing 入口</li><li>interactive turn 依赖装配</li><li>mirror runtime 装配</li><li>session health runtime 装配</li><li>startup notice</li><li>auto task</li><li>tmux/pty 运行中特例</li><li>stop/cleanup</li></ul><p>风险：</p><ul><li>新增功能容易直接在 manager 中插入特例。</li><li>生命周期状态散落在同一个全局 state 对象。</li><li>单元测试需要构造过多无关依赖。</li><li>很难从代码结构看出“进程生命周期”和“业务消息处理”哪个是主轴。</li></ul><h3 id="_2-channels-feishu-adapter-ts-同时承担平台连接、转换、发送和卡片状态机" tabindex="-1">2. <code>channels/feishu/adapter.ts</code> 同时承担平台连接、转换、发送和卡片状态机 <a class="header-anchor" href="#_2-channels-feishu-adapter-ts-同时承担平台连接、转换、发送和卡片状态机" aria-label="Permalink to &quot;2. `channels/feishu/adapter.ts` 同时承担平台连接、转换、发送和卡片状态机&quot;">​</a></h3><p>该文件同时处理：</p><ul><li>WSClient/EventDispatcher。</li><li>飞书 inbound 内容解析、附件下载、mention 清洗。</li><li>outbound text/post/card/file/reaction。</li><li>权限卡片和普通 rich card。</li><li>streaming card 的复杂增量刷新状态。</li><li>chat/group 管理。</li></ul><p>风险：</p><ul><li>Feishu 平台协议变化会影响 stream card 逻辑的可读性。</li><li>卡片状态机难以单独压测。</li><li>通用 channel contract 与 Feishu CardKit 细节交织。</li></ul><h3 id="_3-command-dispatch-仍是集中式大-switch" tabindex="-1">3. Command dispatch 仍是集中式大 switch <a class="header-anchor" href="#_3-command-dispatch-仍是集中式大-switch" aria-label="Permalink to &quot;3. Command dispatch 仍是集中式大 switch&quot;">​</a></h3><p><code>bridge/command/dispatch.ts</code> 已拆出不少 handler，但入口仍是一个大 switch。</p><p>风险：</p><ul><li>命令增加时冲突和顺序规则不显式。</li><li>callback、form、slash 文本和 command alias 的关系难以整体审计。</li><li>每次修改一个命令都容易需要理解整个 dispatch。</li></ul><h3 id="_4-stream-feedback-与平台能力协商分散" tabindex="-1">4. Stream feedback 与平台能力协商分散 <a class="header-anchor" href="#_4-stream-feedback-与平台能力协商分散" aria-label="Permalink to &quot;4. Stream feedback 与平台能力协商分散&quot;">​</a></h3><p><code>runInteractiveMessage()</code>、<code>stream-ui-controller.ts</code>、Feishu adapter 和 mirror feedback controller 都需要知道某种形式的 stream UI 能力。</p><p>风险：</p><ul><li>最终消息是否跳过、卡片是否 active、状态是否 persistent 的判断分散。</li><li>新增通道时，容易复制 Feishu 的隐含行为。</li></ul><h3 id="_5-runtime-provider-的进程模型没有统一生命周期视图" tabindex="-1">5. Runtime provider 的进程模型没有统一生命周期视图 <a class="header-anchor" href="#_5-runtime-provider-的进程模型没有统一生命周期视图" aria-label="Permalink to &quot;5. Runtime provider 的进程模型没有统一生命周期视图&quot;">​</a></h3><p>SDK、pty、tmux、Claude tmux/pty 的实际运行体不同，但对外都叫 provider。</p><p>风险：</p><ul><li>用户和维护者难以判断“当前到底有哪些进程仍在运行”。</li><li>stop/force stop/append input/screen capture 这些行为在 provider 之间语义不同。</li><li>UI status 难以解释 tmux server、pty child、SDK exec 子进程和 mirror JSONL 的关系。</li></ul><h2 id="解耦建议" tabindex="-1">解耦建议 <a class="header-anchor" href="#解耦建议" aria-label="Permalink to &quot;解耦建议&quot;">​</a></h2><h3 id="优先级-p1-拆薄-bridge-manager" tabindex="-1">优先级 P1：拆薄 Bridge manager <a class="header-anchor" href="#优先级-p1-拆薄-bridge-manager" aria-label="Permalink to &quot;优先级 P1：拆薄 Bridge manager&quot;">​</a></h3><p>目标不是一次性重写，而是先把生命周期轴线命名清楚。</p><p>建议拆出：</p><ul><li><code>BridgeApplication</code>：只负责 start/stop 和组合服务。</li><li><code>ChannelIngressService</code>：adapter loop、lane/session 调度、message ack。</li><li><code>MessageRouter</code>：权限快捷回复、terminal append、command、ordinary prompt 的分流。</li><li><code>TurnOrchestrator</code>：包装 <code>runInteractiveMessage()</code> 所需依赖，隔离 manager 对 turn 的装配细节。</li><li><code>BridgeLifecycleState</code>：收敛 daemon 内全局 state，不让每个 feature 直接扩展 manager state。</li></ul><p>验收标准：</p><ul><li><code>bridge/host/manager.ts</code> 不再直接包含普通消息的完整路由细节。</li><li>adapter loop 和 <code>handleMessage()</code> 可独立单测。</li><li>mirror、health、auto task 的装配入口仍在应用层，但业务逻辑不留在应用层。</li></ul><h3 id="优先级-p1-拆-feishu-adapter-的四个角色" tabindex="-1">优先级 P1：拆 Feishu adapter 的四个角色 <a class="header-anchor" href="#优先级-p1-拆-feishu-adapter-的四个角色" aria-label="Permalink to &quot;优先级 P1：拆 Feishu adapter 的四个角色&quot;">​</a></h3><p>建议拆出：</p><ul><li><code>FeishuEventSource</code>：启动 WSClient，注册 EventDispatcher，只发出平台事件。</li><li><code>FeishuInboundMapper</code>：平台事件和内容下载转换成 <code>InboundMessage</code>。</li><li><code>FeishuOutboundClient</code>：发送 text/post/card/file/reaction/group 操作。</li><li><code>FeishuStreamingCardController</code>：CardKit v2 state、flush plan、batch update、full refresh。</li></ul><p>验收标准：</p><ul><li><code>BaseChannelAdapter</code> 实现文件主要做组合。</li><li>streaming card controller 可以用 fake outbound client 做单元测试。</li><li>inbound mapper 可以用录制的平台 payload 做纯函数测试。</li></ul><h3 id="优先级-p2-命令注册表化" tabindex="-1">优先级 P2：命令注册表化 <a class="header-anchor" href="#优先级-p2-命令注册表化" aria-label="Permalink to &quot;优先级 P2：命令注册表化&quot;">​</a></h3><p>把大 switch 逐步收敛成 registry：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> BridgeCommandHandler</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  names</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[];</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  scope</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;channel&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;session&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;global&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ctx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> BridgeCommandContext</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Promise</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BridgeCommandResult</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>短期不需要重写所有命令。可以先让现有 handler 通过 registry 调用，保留 command alias 和 presentation。</p><p>验收标准：</p><ul><li>新增命令不需要修改一个超长 switch。</li><li>命令 scope、是否需要 session、是否允许无绑定，在元数据中可见。</li><li>callback/form command 能和 slash command 使用同一套 command result。</li></ul><h3 id="优先级-p2-建立-runtime-process-registry" tabindex="-1">优先级 P2：建立 Runtime Process Registry <a class="header-anchor" href="#优先级-p2-建立-runtime-process-registry" aria-label="Permalink to &quot;优先级 P2：建立 Runtime Process Registry&quot;">​</a></h3><p>新增一个只读 registry，统一描述当前 runtime 运行体：</p><ul><li>daemon PID。</li><li>UI PID。</li><li>adapter running state。</li><li>SDK active task。</li><li>pty child/session。</li><li>tmux session/pane。</li><li>mirror subscription file path、dirty、last reconciled。</li></ul><p>它不一定负责控制生命周期，先负责解释生命周期。</p><p>验收标准：</p><ul><li><code>/status</code> 和 UI status 可以显示“当前有哪些本地运行体”。</li><li>stop/force stop 可以记录自己实际停止了哪个运行体。</li><li>文档中的进程拓扑能从代码 API 读出来，而不是靠人工推断。</li></ul><h3 id="优先级-p3-收敛-stream-ui-能力协商" tabindex="-1">优先级 P3：收敛 Stream UI 能力协商 <a class="header-anchor" href="#优先级-p3-收敛-stream-ui-能力协商" aria-label="Permalink to &quot;优先级 P3：收敛 Stream UI 能力协商&quot;">​</a></h3><p>定义一个 runtime-neutral 的 <code>StreamUiCapability</code> 或 <code>StreamDeliveryPolicy</code>：</p><ul><li>是否支持 structured streaming card。</li><li>是否支持 persistent status。</li><li>final text 是否由 card 承载。</li><li>card active 判断方式。</li><li>fallback delivery 策略。</li></ul><p>验收标准：</p><ul><li><code>runInteractiveMessage()</code> 不需要理解 Feishu 的特殊判断。</li><li>新通道可以显式声明能力，而不是靠存在某些 optional method 推断全部行为。</li></ul><h3 id="优先级-p3-把-mirror-parser-和-delivery-的测试矩阵文档化" tabindex="-1">优先级 P3：把 mirror parser 和 delivery 的测试矩阵文档化 <a class="header-anchor" href="#优先级-p3-把-mirror-parser-和-delivery-的测试矩阵文档化" aria-label="Permalink to &quot;优先级 P3：把 mirror parser 和 delivery 的测试矩阵文档化&quot;">​</a></h3><p>Mirror 的复杂度合理，但需要固定测试面：</p><ul><li>JSONL partial line。</li><li>file rotation / truncation。</li><li>duplicated assistant text。</li><li>task_started/task_complete 缺失。</li><li>active turn terminal claim。</li><li>suppression window。</li><li>blocked session pending delivery。</li></ul><p>验收标准：</p><ul><li>每个 mirror 边界都有至少一组单元测试或 harness scenario。</li><li>修改 parser 或 delivery plan 时，维护者能知道必须跑哪些测试。</li></ul><h2 id="建议演进顺序" tabindex="-1">建议演进顺序 <a class="header-anchor" href="#建议演进顺序" aria-label="Permalink to &quot;建议演进顺序&quot;">​</a></h2><ol><li>先做 Runtime Process Registry，只读、低风险，立刻改善可观测性和维护者理解。</li><li>拆 <code>MessageRouter</code> 和 <code>ChannelIngressService</code>，把 manager 的消息主路径拿出来。</li><li>拆 Feishu streaming card controller，因为这是最重的单文件状态机。</li><li>命令 registry 化，降低后续命令增长成本。</li><li>收敛 stream UI capability，让新通道接入更可控。</li></ol><h2 id="不建议做的事" tabindex="-1">不建议做的事 <a class="header-anchor" href="#不建议做的事" aria-label="Permalink to &quot;不建议做的事&quot;">​</a></h2><ul><li>不建议引入通用 Observable、FRP 或全局 signal 框架。当前复杂度来自外部平台和 runtime 生命周期，不来自缺少响应式抽象。</li><li>不建议把 mirror、SDK stream、Feishu card update 合并成一个“事件总线”。它们的失败模式不同，强行统一会掩盖重要边界。</li><li>不建议先做大规模目录搬迁。先用小服务抽取和测试固定边界，再移动文件。</li><li>不建议让 ChannelChat 直接绑定 Codex thread。当前 <code>ChannelChat -&gt; BridgeSession -&gt; runtime identity</code> 的间接层是正确的产品边界。</li></ul><h2 id="一句话结论" tabindex="-1">一句话结论 <a class="header-anchor" href="#一句话结论" aria-label="Permalink to &quot;一句话结论&quot;">​</a></h2><p>CodeLark 当前最需要的不是更强的 stream/signal 抽象，而是更清晰的生命周期视图和更薄的编排层。优先把 <code>bridge/host/manager.ts</code> 和 <code>channels/feishu/adapter.ts</code> 的职责拆开，同时强化 <code>UnifiedTurnProgressState</code> 作为内部语义边界。</p>',82)])])}const m=i(r,[["render",l]]);export{u as __pageData,m as default};
